function makeCounter() {
  let count = 0;
  return {
    inc() { count += 1; },
    value() { return count; },
  };
}

const counter = makeCounter();
counter.inc();
console.log(counter.value()); // 1

const workshop = {
  title: "JS Mastery",
  regular() { return this.title; },
  arrow: () => this,
};

const detached = workshop.regular;
console.log(workshop.regular());     // "JS Mastery"
console.log(detached());             // undefined in strict mode
console.log(detached.bind(workshop)()); // "JS Mastery"

function Workshop(title) {
  this.title = title;
}

Workshop.prototype.describe = function () {
  return `Workshop: ${this.title}`;
};

const js = new Workshop("JavaScript Internals");
console.log(js.describe()); // Workshop: JavaScript Internals
console.log(Object.getPrototypeOf(js) === Workshop.prototype); // true

const countdown = {
  from: 3,
  [Symbol.iterator]() {
    let current = this.from;
    return {
      next() {
        if (current < 0) {
          return { done: true };
        }
        return { value: current--, done: false };
      },
    };
  },
};

console.log([...countdown]); // [3, 2, 1, 0]

